#include<bits/stdc++.h>
using namespace std;
int trietot;
int u[10000010][2],v[10000010][2];
struct trie
{
    vector<array<int,27>> son;
    vector<int> dfn,siz;
    int dfncnt,cnt;
    int addnode()
    {
        son.push_back({});
        dfn.push_back(0);
        siz.push_back(0);
        return (int)(dfn.size()-1);
    }
    trie()
    {
        cnt=++trietot;
        dfncnt=0;
        son.clear();
        dfn.clear();
        siz.clear();
        addnode();
    }
    void clear()
    {
        dfncnt=0;
        son.clear();
        dfn.clear();
        siz.clear();
        addnode();
    }
    void addtreenode(int p,int c)
    {
        int now=addnode();
        son[p][c]=now;
    }
    void insert(const char s[],int col,int id1)
    {
        int p=0;
        for(int i=0;s[i];i++)
        {
            int c=s[i]-'a';
            if(!son[p][c])
            {
                addtreenode(p,c);
            }
            p=son[p][c];
        }
        if(col==0)
        {
            u[id1][cnt]=p;
        }
        else
        {
            v[id1][cnt]=p;
        }
    }
    void dfs(int x)
    {
        siz[x]=1;
        dfn[x]=++dfncnt;
        for(int i=0;i<26;i++)if(son[x][i])
        {
            dfs(son[x][i]);
            siz[x]+=siz[son[x][i]];
        }
    }
    void rundfs()
    {
        dfncnt=0;
        dfs(0);
    }
};
trie p;
trie q;
struct fenwick
{
    int lowbit(int x)
    {
        return x&-x;
    }
    int sum[5000010],lstclear[5000010],clearcnt;
    fenwick()
    {
        clearcnt=0;
        memset(sum,0,sizeof(sum));
    }
    void clear()
    {
        clearcnt++;
    }
    void add(int x,int v)
    {
        x++;
        for(int i=x;i<=5000001;i+=lowbit(i))
        {
            if(lstclear[i]!=clearcnt)
            {
                lstclear[i]=clearcnt;
                sum[i]=0;
            }
            sum[i]+=v;
        }
    }
    int query(int x)
    {
        x++;
        int ans=0;
        for(int i=x;i>=1;i-=lowbit(i))
        {
            if(lstclear[i]!=clearcnt)
            {
                lstclear[i]=clearcnt;
                sum[i]=0;
            }
            ans+=sum[i];
        }
        return ans;
    }
}t;

//////////////////////////////////////

int n,q_p1;
char s1[5000010],s2[5000010],s[5000010];
int ans[5000010];
struct node
{
    string a,b;
    int id;
};
unordered_map<string,vector<node> > mp_s,mp_t;
struct segment
{
    int x,l,r,val;
    bool operator<(const segment&b)const
    {
        return x<b.x;
    }
};
struct point
{
    int x,y,id;
    bool operator<(const point&b)const
    {
        return y<b.y;
    }
};

//////////////////////////////////////
void part1()
{
    scanf("%d%d",&n,&q_p1);
    for(int i=1;i<=n;i++)
    {
        scanf("%s%s",s1+1,s2+1);
        int m=strlen(s1+1);
        int l=1,r=m;
        while(l<=m&&s1[l]==s2[l])
        {
            l++;
        }
        while(r>=1&&s1[r]==s2[r])
        {
            r--;
        }
        if(l>r)
        {
            continue;
        }
        int tot=0;
        for(int j=l;j<=r;j++)
        {
            s[tot++]=s1[j];
        }
        for(int j=l;j<=r;j++)
        {
            s[tot++]=s2[j];
        }
        s[tot]='\0';
        string str=s,str1,str2;
        tot=0;
        for(int j=l-1;j>=1;j--)
        {
            s[tot++]=s1[j];
        }
        s[tot]='\0';
        str1=s;
        tot=0;
        for(int j=r+1;j<=m;j++)
        {
            s[tot++]=s1[j];
        }
        s[tot]='\0';
        str2=s;
        mp_s[str].push_back((node){str1,str2,i});
    }
    for(int i=1;i<=q_p1;i++)
    {
        scanf("%s%s",s1+1,s2+1);
        int m=strlen(s1+1),len=strlen(s2+1);
        if(m!=len)
        {
            ans[i]=0;
            continue;
        }
        int l=1,r=m;
        while(l<=m&&s1[l]==s2[l])
        {
            l++;
        }
        while(r>=1&&s1[r]==s2[r])
        {
            r--;
        }
        int tot=0;
        for(int j=l;j<=r;j++)
        {
            s[tot++]=s1[j];
        }
        for(int j=l;j<=r;j++)
        {
            s[tot++]=s2[j];
        }
        s[tot]='\0';
        string str=s,str1,str2;
        tot=0;
        for(int j=l-1;j>=1;j--)
        {
            s[tot++]=s1[j];
        }
        s[tot]='\0';
        str1=s;
        tot=0;
        for(int j=r+1;j<=m;j++)
        {
            s[tot++]=s1[j];
        }
        s[tot]='\0';
        str2=s;
        mp_t[str].push_back((node){str1,str2,i});
    }
}
void part2()
{
    vector<segment> vec_s;
    vector<point> vec_p;
    for(auto i:mp_s)
    {
        string core=i.first;
        vector<node> nows=i.second,nowt=mp_t[core];
        if(nowt.empty())
        {
            continue;
        }
        p.clear();
        q.clear();
        for(node j:nows)
        {
            p.insert(j.a.c_str(),0,j.id);
            q.insert(j.b.c_str(),0,j.id);
        }
        for(node j:nowt)
        {
            p.insert(j.a.c_str(),1,j.id);
            q.insert(j.b.c_str(),1,j.id);
        }
        p.rundfs();
        q.rundfs();
        t.clear();
        vec_s.clear();
        vec_p.clear();
        for(node j:nows)
        {
            vec_s.push_back((segment){q.dfn[u[j.id][2]],p.dfn[u[j.id][1]],p.dfn[u[j.id][1]]+p.siz[u[j.id][1]]-1,1});
            vec_s.push_back((segment){q.dfn[u[j.id][2]]+q.siz[u[j.id][2]],p.dfn[u[j.id][1]],p.dfn[u[j.id][1]]+p.siz[u[j.id][1]]-1,-1});
        }
        for(node j:nowt)
        {
            vec_p.push_back((point){p.dfn[v[j.id][1]],q.dfn[v[j.id][2]],j.id});
        }
        sort(vec_s.begin(),vec_s.end());
        sort(vec_p.begin(),vec_p.end());
        int k=0;
        for(auto j:vec_p)
        {
            while(k<vec_s.size()&&vec_s[k].x<=j.y)
            {
                t.add(vec_s[k].l,vec_s[k].val);
                t.add(vec_s[k].r+1,-vec_s[k].val);
                k++;
            }
            ans[j.id]=t.query(j.x);
        }
    }
}
void part3()
{
    for(int i=1;i<=q_p1;i++)
    {
        printf("%d\n",ans[i]);
    }
}
int main()
{
    part1();
    part2();
    part3();
    return 0;
}
